// === INTERFACES ENTERPRISE COMPLETAS ===
interface UserProfile {
  id: string;
  name: string;
  email: string;
  plan: 'free' | 'trial' | 'basic' | 'pro' | 'enterprise';
  trial_end?: string;
  subscription_status: 'active' | 'canceled' | 'past_due' | 'trialing';
  next_billing_date?: string;
  created_at: string;
  updated_at?: string;
  // ✅ Campos essenciais para o backend
  company_name?: string;
  phone?: string;
  country: string;
  timezone: string;
  currency: 'BRL' | 'USD' | 'EUR';
  tax_id?: string;
}

interface UserSettings {
  id?: string;
  client_id: string;
  // ✅ Notificações e relatórios
  notifications_enabled: boolean;
  email_notifications: boolean;
  sms_notifications: boolean;
  webhook_notifications: boolean;
  email_reports: boolean;
  auto_optimization: boolean;
  report_frequency: 'daily' | 'weekly' | 'monthly';
  report_format: 'pdf' | 'excel' | 'dashboard';
  // ✅ Configurações do sistema
  timezone: string;
  language: 'pt-BR' | 'en-US' | 'es-ES';
  currency: 'BRL' | 'USD' | 'EUR';
  theme: 'light' | 'dark' | 'auto';
  // ✅ API e integrações
  api_access_enabled: boolean;
  webhook_url?: string;
  slack_webhook?: string;
  // ✅ ML/RL settings
  ml_enabled: boolean;
  rl_enabled: boolean;
  ab_testing_enabled: boolean;
  optimization_aggressiveness: 'conservative' | 'moderate' | 'aggressive';
  seasonality_adjustment: boolean;
  data_retention_days: number;
}

interface SiteConfig {
  id?: string;
  url: string;
  client_id: string;
  // ✅ ESSENCIAL: Informações para analyze-adsense
  name: string;
  category: SiteCategory;
  content_niche?: string; // Descrição do conteúdo para detectNicheWithScoring
  country: string;
  primary_region: BrazilianRegion;
  language: string;
  // ✅ Geographic distribution para analyze-adsense
  geographic_distribution?: Array<{
    region: BrazilianRegion;
    percentage: number;
    tier: number;
  }>;
  // ✅ Métricas e configurações
  monthly_pageviews?: number;
  current_rpm?: number;
  target_rpm?: number;
  script_installed: boolean;
  optimization_enabled: boolean;
  // ✅ Integrações
  adsense_id?: string;
  analytics_id?: string;
  // ✅ Configurações avançadas de otimização
  optimization_token?: string;
  api_enabled: boolean;
  webhook_enabled: boolean;
  ab_testing_enabled: boolean;
  mobile_optimization: boolean;
  lazy_loading_enabled: boolean;
  ad_placement_auto: boolean;
  targeting_enabled: boolean;
  cache_enabled: boolean;
  cache_ttl: number;
  cdn_enabled: boolean;
  created_at: string;
  updated_at?: string;
}

interface RateLimitInfo {
  id: string;
  client_id: string;
  plan_type: string;
  analyses_count: number;
  analyses_limit: number;
  sites_count: number;
  sites_limit: number;
  api_calls_count: number;
  api_calls_limit: number;
  reset_date: string;
  last_updated: string;
}

interface PlanFeature {
  name: string;
  limit?: number | string;
  included: boolean;
  description?: string;
}

interface Plan {
  id: string;
  name: string;
  price: number;
  currency: string;
  billing_period: 'monthly' | 'yearly';
  features: PlanFeature[];
  popular?: boolean;
  enterprise?: boolean;
}

// === ANIMATION KEYFRAMES ENTERPRISE ===
const slideInUp = keyframes`
  from { opacity: 0; transform: translateY(24px) scale(0.98); }
  to { opacity: 1; transform: translateY(0) scale(1); }
`;

const saveSuccess = keyframes`
  0% { background: linear-gradient(135deg, #30D158 0%, #34C759 100%); }
  50% { background: linear-gradient(135deg, #00C851 0%, #30D158 100%); }
  100% { background: linear-gradient(135deg, #30D158 0%, #34C759 100%); }
`;

const upgradeShine = keyframes`
  0% { transform: translateX(-100%); opacity: 0; }
  50% { opacity: 1; }
  100% { transform: translateX(100%); opacity: 0; }
`;

